Here is code for a Discord bot with a slash command to ban users:

```js
const { Client, ChatInputCommandInteraction, PermissionFlagsBits } = require('discord.js');

const client = new Client({ intents: [] });

client.on('ready', () => {
  console.log('Ready!');

  client.application.commands.create({
    name: 'ban',
    description: 'Bans a user',
    defaultPermission: false,
    options: [
      {
        name: 'user',
        description: 'The user to ban',
        type: 'USER',
        required: true
      },
      {
        name: 'reason',
        description: 'The reason for the ban',
        type: 'STRING',
        required: false
      }
    ]
  });
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isChatInputCommand()) return;

  if (interaction.commandName === 'ban') {
    if (!interaction.member.permissions.has(PermissionFlagsBits.BanMembers)) {
      return interaction.reply({ content: 'You do not have permission to use this command!', ephemeral: true });
    }

    const user = interaction.options.getMember('user');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    await interaction.guild.members.ban(user, { reason });

    await interaction.reply(`Banned ${user.user.tag} for "${reason}"`);
  }
});

client.login('token');
```

The key points:

- Create a slash command using `client.application.commands.create()`
- Check for Ban Members permission before banning
- Get the user to ban from the interaction options 
- Ban the user with `interaction.guild.members.ban()`
- Reply to the interaction to confirm the ban

