Here is a detailed C++ function to convert markdown to HTML:

```cpp
#include <iostream>
#include <string>

std::string markdownToHtml(std::string &mdText) {
    std::string html;

    // Iterate through markdown text 
    for(int i = 0; i < mdText.length(); i++) {

        // Check for markdown headers
        if(mdText[i] == '#') {
            html += "<h";
            i++;
            while(mdText[i] == '#') {
                html += std::to_string(mdText[i] - '0'); 
                i++;
            }
            html += ">";

        // Check for markdown emphasis 
        } else if(mdText[i] == '*' && mdText[i-1] != '\\') {
            html += "<em>";

        } else if(mdText[i] == '*' && mdText[i+1] != '\\') {
            html += "</em>";

        // Check for markdown links  
        } else if(mdText[i] == '[' && mdText[i-1] != '\\') {
            int linkEnd = mdText.find("]", i);
            int urlStart = mdText.find("(", i);
            int urlEnd = mdText.find(")", urlStart);
            std::string linkText = mdText.substr(i+1, linkEnd - i - 1);
            std::string url = mdText.substr(urlStart + 1, urlEnd - urlStart - 1);
            html += "<a href=\"" + url + "\">" + linkText + "</a>";
            i = urlEnd;

        // Default - escape text  
        } else {
            html += mdText[i];
        }
    }

    return html;
}
```

The key steps are:

1. Iterate through the markdown text character by character
2. Check for markdown syntax like headers, emphasis, links 
3. Generate corresponding HTML tags 
4. Escape any regular text

